      interview: [
        { level: "Junior", q: "What is useSelector?", a: "A hook that allows your React components to read data from the Redux store.", type: "Conceptual" },
        { level: "Junior", q: "What is useDispatch?", a: "A hook that returns a reference to the dispatch function from the Redux store, used to send actions.", type: "Conceptual" },
        { level: "Junior", q: "How do you dispatch an action with a payload?", a: "By calling dispatch(actionCreator(data)).", type: "Coding" },
        { level: "Junior", q: "What is a 'Selector'?", a: "A function that takes the Redux state as an argument and returns some data from it.", type: "Conceptual" },
        { level: "Junior", q: "Can you use multiple useSelector hooks in one component?", a: "Yes, you can call it as many times as needed to get different pieces of state.", type: "Conceptual" },
        { level: "Junior", q: "What is strict equality (===) comparison in useSelector?", a: "It means if the reference to the data hasn't changed, the component won't re-render.", type: "Conceptual" },
        { level: "Junior", q: "How do you call dispatch inside a useEffect?", a: "By including 'dispatch' in the dependency array (which is stable) and calling it inside the effect body.", type: "Coding" },
        { level: "Junior", q: "What happens if you use a selector like state => state?", a: "Your component will re-render whenever ANY part of the store changes, which is bad for performance.", type: "Scenario" },
        { level: "Junior", q: "What is the 'connect' function?", a: "The older, HOC-based way to connect components to Redux before hooks were introduced.", type: "Conceptual" },
        { level: "Junior", q: "Difference between useStore and useSelector?", a: "useStore gives you the entire store object, while useSelector is the preferred way to subscribe to specific data changes.", type: "Conceptual" },
        { level: "Junior", q: "Can you dispatch an action in the body of a functional component?", a: "No, it should be done in an event handler or a useEffect to avoid side effects during rendering.", type: "Scenario" },
        { level: "Junior", q: "What is 'Prop Drilling' and how does Redux stop it?", a: "The process of passing data through components that don't need it. Redux makes data available directly via hooks.", type: "Conceptual" },
        { level: "Junior", q: "What is result of calling useDispatch()?", a: "The store's dispatch function.", type: "Conceptual" },
        { level: "Mid", q: "How does useSelector optimize performance?", a: "It compares the result of the selector function with the previous result using strict equality (===). If they are the same, it doesn't re-render.", type: "Conceptual" },
        { level: "Mid", q: "What is a Selector function?", a: "A function that takes the entire Redux state as an argument and returns a specific piece of it.", type: "Conceptual" },
        { level: "Mid", q: "Difference between useSelector(state => state.user) and useSelector(state => state.user.name)?", a: "The first re-renders if ANY field in user changes. The second ONLY re-renders if 'name' specifically changes.", type: "Conceptual" },
        { level: "Mid", q: "Why use 'createSelector' from RTK/Reselect?", a: "To create memoized selectors that only re-calculate their output if the input state slices have changed, protecting performance for expensive derivations.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle 'Derived State' in Redux?", a: "By doing the calculation inside a selector rather than storing the calculated value in the store (e.g., total price).", type: "Conceptual" },
        { level: "Mid", q: "What is the 'shallowEqual' equality function?", a: "A built-in comparison function you can pass to useSelector to allow re-rendering only when object properties change, not just references.", type: "Conceptual" },
        { level: "Mid", q: "How do you test a selector function?", a: "By calling it with a mock state object and asserting that it returns the expected value.", type: "Coding" },
        { level: "Mid", q: "Can you use local state (useState) and Redux together?", a: "Yes, Redux for global shared state and useState for UI-only state like 'isMenuOpen'.", type: "Scenario" },
        { level: "Mid", q: "What is 'Batching' in React Redux?", a: "A feature that groups multiple state updates into a single re-render for better performance.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'Selector Composition'.", a: "Building a complex selector by using several smaller selectors as inputs to createSelector.", type: "Conceptual" },
        { level: "Mid", q: "Why is 'dispatch' stable across renders?", a: "Because it's a reference to the store's method, which doesn't change for the lifetime of the store.", type: "Conceptual" },
        { level: "Senior", q: "Explain the 'Identity Reference' issue with useSelector.", a: "If your selector returns a new object/array every time (e.g., using .filter()), it will trigger a re-render on every store change unless memoized.", type: "Scenario" },
        { level: "Senior", q: "How do you handle parameterized selectors (selectors with arguments)?", a: "By creating a factory function or using a memoized selector creator that accepts the parameter (like an ID).", type: "Coding" },
        { level: "Senior", q: "Wait, can I use regular state logic (useState) alongside Redux?", a: "Yes. Use Redux for global/shared data. Use useState for UI-specific state (like 'isModalOpen') that doesn't need to be shared.", type: "Scenario" },
        { level: "Senior", q: "How would you debug a component that's re-rendering too often due to a selector?", a: "Check if the selector is returning a new object reference every time it runs and use createSelector to fix it.", type: "Scenario" },
        { level: "Senior", q: "Why is it better to name your selector functions (e.g., selectUser)?", a: "For reusability across components and easier profiling/debugging in DevTools.", type: "Scenario" },
        { level: "Senior", q: "How do you implement 'Dynamic Selectors' for a list of items?", a: "By creating a selector that takes an ID as an argument and using it in components that represent individual items.", type: "Coding" },
        { level: "Senior", q: "Explain the pros/cons of 'Reselect'.", a: "Pros: Performance, Cache. Cons: Memory usage for huge caches, complexity of implementation.", type: "Conceptual" },
        { level: "Senior", q: "How do you manage 'Cross-Slice' data dependencies in selectors?", a: "By combining input selectors from different slices into one final createSelector.", type: "Scenario" },
        { level: "Senior", q: "What is 'Pre-computing' state for better selector performance?", a: "Formatting or normalizing data in the reducer so that selectors have very little work to do.", type: "Scenario" },
        { level: "Senior", q: "Design a selector for a search-and-filter feature.", a: "A createSelector that takes 'allData', 'searchQuery', and 'filterType' as inputs and returns only matching items.", type: "Coding" },
        { level: "Senior", q: "How do you handle 'Recursive' state structures in selectors?", a: "By creating memoized selectors that can call themselves or handle tree traversal efficiently.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Selective Hydration' with selectors.", a: "Only rendering components whose selectors have updated, even if the root state has changed.", type: "Conceptual" },
        { level: "Senior", q: "How to handle 'Expensive' data transformations in Redux?", a: "Offload them to a specialized memoized selector or a Web Worker if they are extremely heavy.", type: "Scenario" },
        { level: "Senior", q: "Why avoid using 'this' in selector functions?", a: "Because they should be pure, stateless functions that only depend on the passed Redux state.", type: "Conceptual" },
        { level: "Senior", q: "Explain 'Redux Thunk' access to state via selectors.", a: "Thunks get 'getState' which can be passed to selectors manually to read data before an async call.", type: "Coding" },
        { level: "Senior", q: "How would you implement 'Global Loader' state using selectors and middleware?", a: "Middleware sets a global 'loading' flag; selectors provide it to the main layout for a progress bar.", type: "Scenario" }
      ]
